<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Sorting Algorithm Visualizer</title>
<style>
  body { margin:0; font-family:sans-serif; background:#121212; color:#eee; display:flex; flex-direction:column; align-items:center; height:100vh;}
  #controls{margin:10px;}
  button{margin:5px;padding:8px 12px;background:#333;color:white;border:none;border-radius:4px;cursor:pointer;}
  button:hover{background:#444;}
  #bars{display:flex;align-items:flex-end;width:90%;height:60%;border:1px solid #555;margin-top:10px;}
  .bar{flex:1;margin:0 2px;background:#bb86fc;transition:all 0.3s ease;}
</style>
</head>
<body>

<div id="controls">
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
  <button id="sort">Sort</button>
</div>
<div id="bars"></div>

<script>
(() => {
  const N = 30; // number of bars
  let arr = [];
  let sortedFlag = false;
  let i=0, j=0; // bubble sort indices

  function render() {
    const container=document.getElementById('bars');
    container.innerHTML='';
    arr.forEach(v=>{
      const bar=document.createElement('div');
      bar.className='bar';
      bar.style.height=`${v}%`;
      container.appendChild(bar);
    });
  }

  function shuffleArray() {
    for(let i=arr.length-1;i>0;i--){
      const j=Math.floor(Math.random()*(i+1));
      [arr[i],arr[j]]=[arr[j],arr[i]];
    }
  }

  // API
  window.viz = {
    array: () => arr.slice(),
    setArray: (a) => { arr=a.slice(); sortedFlag=false; i=0;j=0; render(); },
    sortStep: () => {
      if(sortedFlag)return true;
      if(i>=arr.length-1){sortedFlag=true;return true;}
      if(j>=arr.length-i-1){i++;j=0;return false;}
      if(arr[j]>arr[j+1]) [arr[j],arr[j+1]]=[arr[j+1],arr[j]];
      j++;
      render();
      return sortedFlag;
    },
    sorted: () => sortedFlag
  };

  // init array
  arr = Array.from({length:N},(_,k)=>Math.floor((k+1)/N*100));
  shuffleArray();
  render();

  document.getElementById('shuffle').onclick=()=>{shuffleArray();render();};
  document.getElementById('reset').onclick=()=>{arr.sort((a,b)=>a-b);sortedFlag=true;render();};
  document.getElementById('sort').onclick=()=>{
    const interval=setInterval(()=>{
      if(window.viz.sortStep()){clearInterval(interval);}
    },200);
  };
})();
</script>
</body>
</html>
